import React , { useState,useEffect }  from "react";
import logo from "./images/logo.jpeg";
import AiTeacher from "./images/aiBackground.jpg";
import Container from 'react-bootstrap/Container';
import Nav from 'react-bootstrap/Nav';
import Navbar from 'react-bootstrap/Navbar';
import "./upload.css";
import Row from 'react-bootstrap/Row';
import Col from 'react-bootstrap/Col';
import Button from 'react-bootstrap/Button';
import Form from 'react-bootstrap/Form';
import { useNavigate ,Link } from 'react-router-dom';
import styled from 'styled-components';
import Card from 'react-bootstrap/Card';
import { useSpeechSynthesis } from 'react-speech-kit';


function UploadPage() {
  const [pdfText, setPdfText] = useState('');
  const [file, setFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const { speak, cancel } = useSpeechSynthesis();

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
  };

  const handleUpload = async () => {
    if (!file) {
      alert('Please select a PDF file.');
      return;
    }

    setLoading(true);

    const formData = new FormData();
    formData.append('pdf', file);

    try {
      const response = await fetch('http://localhost:5000/upload', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        const errorMessage = await response.text();
        throw new Error(errorMessage || 'Failed to upload or parse PDF');
      }

      const data = await response.json();
      setPdfText(data.content);
    } catch (error) {
      console.error('Error uploading PDF:', error);
      alert('An error occurred while uploading the file. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      <Navbar bg="light" variant="light" expand="lg">
        <Container>
          <Navbar.Brand href="#home">
            <img
              src={logo}
              width="30"
              height="30"
              className="d-inline-block align-top"
              alt="React Bootstrap logo"
            />
          </Navbar.Brand>
          <Navbar.Toggle aria-controls="basic-navbar-nav" />
          <Navbar.Collapse id="basic-navbar-nav">
            <Nav className="me-auto">
              <Nav.Link as={Link} to="/home">
                Home
              </Nav.Link>
              <Nav.Link as={Link} to="/">
                Login
              </Nav.Link>
              <Nav.Link as={Link} to="/register">
                Registration
              </Nav.Link>
            </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>
        <div className="form-container">
      <div className="">
        <h4>Choose a Chapter</h4>
        <Form>
          <Form.Group className="mb-3" controlId="formBasicFile">
            <Form.Label>Select File</Form.Label>
            <Form.Control type="file" accept="application/pdf" onChange={handleFileChange} />
          </Form.Group>
          <Button
            variant="danger"
            type="submit"
            onClick={(e) => {
              e.preventDefault();
              handleUpload();
            }}
          >
            Submit
          </Button>
        </Form>
        </div>
        {loading && <p>Uploading and processing file...</p>}
        <div className="pdf-content">
          <h4>Extracted Content:</h4>
          <p>{pdfText || 'No content available. Please upload a PDF.'}</p>
        </div>
      </div>
    </div>
  );
}

export default UploadPage;
